                // Check for '&' (return by reference)
                if ($j < $token_count && is_string($tokens[$j]) && $tokens[$j] === '&') { $j++; }
                while ($j < $token_count && is_array($tokens[$j]) && $tokens[$j][0] === T_WHITESPACE) $j++;
                
                $is_named = ($j < $token_count && is_array($tokens[$j]) && $tokens[$j][0] === T_STRING);
                $is_closure = !$is_named; // 'function' not followed by a name = closure
                
                if ($is_named && $j < $token_count) {
