                if (in_array($text, $superglobals, true)) {
                    // Check if preceded by isset/empty
                    $j = $i - 1;
                    while ($j >= 0 && is_array($tokens[$j]) && $tokens[$j][0] === T_WHITESPACE) $j--;
                    $k = $j - 1;
                    while ($k >= 0 && is_array($tokens[$k]) && $tokens[$k][0] === T_WHITESPACE) $k--;
                    
                    $wrapped = false;
